export default function GuestApp() {
  const [tab, setTab] = useState("accueil");
  const [countdown, setCountdown] = useState({});
  const [messages, setMessages] = useState(MESSAGES_INIT);
  const [newMsg, setNewMsg] = useState("");
  const [newName, setNewName] = useState("");
  const [selectedMeal, setSelectedMeal] = useState(null);
  const [rsvpStatus, setRsvpStatus] = useState(null);

  useEffect(() => {
    const tick = () => {
      const now = new Date();
      const diff = WEDDING_DATE_1 - now;
      if (diff <= 0) { setCountdown({ days:0, hours:0, mins:0, secs:0 }); return; }
      setCountdown({
        days: Math.floor(diff / 86400000),
        hours: Math.floor((diff % 86400000) / 3600000),
        mins: Math.floor((diff % 3600000) / 60000),
        secs: Math.floor((diff % 60000) / 1000),
      });
    };
    tick();
    const iv = setInterval(tick, 1000);
    return () => clearInterval(iv);
  }, []);

  const sendMessage = () => {
    if (!newMsg.trim() || !newName.trim()) return;
    const h = new Date().toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" });
    setMessages([{ id: Date.now(), name: newName, msg: newMsg, time: h }, ...messages]);
    setNewMsg(""); setNewName("");
  };

  const confirmed = GUESTS.filter(g => g.confirmed).length;

  const groupedProgram = PROGRAM.reduce((acc, p) => {
    if (!acc[p.date]) acc[p.date] = [];
    acc[p.date].push(p);
    return acc;
  }, {});

  return (
    <>
      <style>{STYLES}</style>
      <div className="app">

        {/* Hero */}
        <div className="hero">
          <img src={img5} alt="Prudence et Praxèd" className="hero-img" />
          <div className="hero-overlay" />
          <div className="hero-content">
            <div className="hero-sub">Célébrons l\'amour !</div>
            <div className="hero-names">
              Prudence
              <span className="hero-and">&amp;</span>
              Praxèd
            </div>
            <div className="hero-date">09 · 11 · Juillet · 2026</div>
            <div className="hero-love">Se disent OUI ❤️ après 16 ans d\'amour</div>
          </div>
        </div>

        {/* Countdown */}
        <div className="countdown">
          {[["days","Jours"],["hours","Heures"],["mins","Min"],["secs","Sec"]].map(([k,l], i) => (
            <div key={k} style={{display:"flex", alignItems:"center", gap: i===0?0:"inherit"}}>
              {i > 0 && <span className="cd-sep" style={{marginRight:8}}>·</span>}
              <div className="cd-unit">
                <div className="cd-num">{String(countdown[k] ?? 0).padStart(2,"0")}</div>
                <div className="cd-label">{l}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div className="tabs">
          {NAV.map(n => (
            <button key={n.id} className={`tab${tab===n.id?" active":""}`} onClick={() => setTab(n.id)}>
              {n.icon} {n.label}
            </button>
          ))}
        </div>

        {/* ACCUEIL */}
        {tab === "accueil" && (
          <div className="section">
            <div className="invite-card">
              <div className="invite-card-sub">Faire-part de mariage</div>
              <div style={{fontFamily:"'Playfair Display',serif", fontSize:13, color:"#f5d9a8", lineHeight:1.8}}>
                C\'est après 16 années d\'amour et de tendresse<br/>
                que nous avons décidé de nous dire oui pour toujours,<br/>
                dans un cadre idyllique.
              </div>
              <div style={{fontFamily:"'Playfair Display',serif", fontSize:13, color:"#e8c89a", marginTop:12, fontStyle:"italic"}}>
                Nous avons hâte de partager ce nouveau chapitre avec vous.
              </div>
              <div className="invite-card-dates">
                <div className="date-box">
                  <div className="date-day">09</div>
                  <div className="date-month">Juil 2026</div>
                  <div className="date-event">Mariage Coutumier</div>
                </div>
                <div className="date-box">
                  <div className="date-day">11</div>
                  <div className="date-month">Juil 2026</div>
                  <div className="date-event">Mariage Civil</div>
                </div>
              </div>
            </div>

            {/* Slider photos */}
            <div style={{paddingLeft:16, marginBottom:4}}>
              <div className="section-title" style={{marginBottom:0}}>Notre histoire</div>
              <div className="section-sub">En images</div>
            </div>
            <div className="slider" style={{paddingLeft:16, paddingRight:16}}>
              {PHOTOS_DATA.map(p => (
                <div className="slide" key={p.id}>
                  <img src={p.src} alt={p.label} />
                  <div className="slide-info">
                    <div className="slide-label">{p.label}</div>
                    <div className="slide-author">{p.author}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* PROGRAMME */}
        {tab === "programme" && (
          <div className="section">
            <div className="section-title">Programme</div>
            <div className="section-sub">Le déroulé des festivités</div>
            {Object.entries(groupedProgram).map(([date, items]) => (
              <div className="prog-date-group" key={date}>
                <span className="prog-date-label">{date}</span>
                {items.map((p, i) => (
                  <div className="program-item" key={i}>
                    <div className="prog-time">{p.time}</div>
                    <div style={{fontSize:26, flexShrink:0}}>{p.icon}</div>
                    <div style={{flex:1}}>
                      <div className="prog-title">{p.title}</div>
                      <div className="prog-desc">{p.desc}</div>
                      <div className="prog-dur">Durée : {p.duration}</div>
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}

        {/* INFOS */}
        {tab === "infos" && (
          <div className="section">
            <div className="section-title">Informations</div>
            <div className="section-sub">Tout ce qu\'il faut savoir</div>
            {INFOS.map((info, i) => (
              <div className="info-card" key={i} style={{background: info.color}}>
                <div className="info-header">
                  <span className="info-icon">{info.icon}</span>
                  <span className="info-title">{info.title}</span>
                </div>
                <div className="info-content">{info.content}</div>
              </div>
            ))}
          </div>
        )}

        {/* RSVP */}
        {tab === "rsvp" && (
          <div className="section">
            <div className="section-title">RSVP</div>
            <div className="section-sub">Confirmez votre présence</div>
            <div className="rsvp-stats">
              <div className="stat-box" style={{background:"#e6f4ea"}}><div className="stat-num" style={{color:"#2d8a4e"}}>{confirmed}</div><div className="stat-label">Confirmés</div></div>
              <div className="stat-box" style={{background:"#fde8e8"}}><div className="stat-num" style={{color:"#c0392b"}}>{GUESTS.length-confirmed}</div><div className="stat-label">En attente</div></div>
              <div className="stat-box" style={{background:"#fdf3e8"}}><div className="stat-num" style={{color:"#8B4513"}}>{GUESTS.length}</div><div className="stat-label">Invités</div></div>
            </div>
            <div className="rsvp-card">
              <div style={{fontFamily:"'Playfair Display',serif", fontSize:18, marginBottom:12, color:"#2a1a0a"}}>Votre présence</div>
              <div style={{display:"flex", gap:10}}>
                <button onClick={() => setRsvpStatus("yes")} style={{flex:1,padding:"12px",borderRadius:12,border:`2px solid ${rsvpStatus==="yes"?"#2d8a4e":"#e0d4c8"}`,background:rsvpStatus==="yes"?"#e6f4ea":"white",color:rsvpStatus==="yes"?"#2d8a4e":"#7a6050",fontFamily:"Nunito,sans-serif",fontSize:13,cursor:"pointer",fontWeight:700,transition:"all 0.2s"}}>✓ Je serai là !</button>
                <button onClick={() => setRsvpStatus("no")} style={{flex:1,padding:"12px",borderRadius:12,border:`2px solid ${rsvpStatus==="no"?"#c0392b":"#e0d4c8"}`,background:rsvpStatus==="no"?"#fde8e8":"white",color:rsvpStatus==="no"?"#c0392b":"#7a6050",fontFamily:"Nunito,sans-serif",fontSize:13,cursor:"pointer",fontWeight:700,transition:"all 0.2s"}}>✗ Absent(e)</button>
              </div>
              {rsvpStatus === "yes" && <div style={{marginTop:10,padding:"10px",background:"#e6f4ea",borderRadius:10,fontSize:13,color:"#2d8a4e"}}>🎉 Merci ! On vous attend avec joie !</div>}
              {rsvpStatus === "no" && <div style={{marginTop:10,padding:"10px",background:"#fde8e8",borderRadius:10,fontSize:13,color:"#c0392b"}}>Vous serez dans nos cœurs 💕</div>}
            </div>
            <div className="rsvp-card">
              <div style={{fontFamily:"'Playfair Display',serif", fontSize:18, marginBottom:12, color:"#2a1a0a"}}>Liste des invités</div>
              {GUESTS.map(g => (
                <div className="guest-row" key={g.id}>
                  <div className="guest-avatar">{g.name[0]}</div>
                  <div style={{flex:1}}>
                    <div className="guest-name">{g.name}</div>
                    {g.meal && <div style={{fontSize:11,color:"#8B6035"}}>{g.meal}</div>}
                  </div>
                  <span className={`badge ${g.confirmed?"badge-yes":"badge-no"}`}>{g.confirmed?"Confirmé":"En attente"}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* PHOTOS */}
        {tab === "photos" && (
          <div className="section">
            <div className="section-title">Galerie</div>
            <div className="section-sub">Nos plus beaux souvenirs</div>
            <div className="gallery-grid">
              {PHOTOS_DATA.map(p => (
                <div className="photo-card" key={p.id}>
                  <img src={p.src} alt={p.label} />
                  <div className="photo-info">
                    <div className="photo-label">{p.label}</div>
                    <div className="photo-author">{p.author}</div>
                  </div>
                </div>
              ))}
            </div>
            <button className="main-btn">📷 Partager une photo</button>
          </div>
        )}

        {/* LIVRE D\'OR */}
        {tab === "or" && (
          <div className="section">
            <div className="section-title">Livre d\'or</div>
            <div className="section-sub">Vos messages aux mariés</div>
            <div className="msg-form">
              <input className="msg-input" style={{marginBottom:8}} placeholder="Votre nom..." value={newName} onChange={e => setNewName(e.target.value)} />
              <textarea className="msg-input" rows={3} placeholder="Écrivez votre message de vœux..." value={newMsg} onChange={e => setNewMsg(e.target.value)} />
              <button className="main-btn" onClick={sendMessage}>Envoyer mon message 💌</button>
            </div>
            {messages.map(m => (
              <div className="message-card" key={m.id}>
                <div className="msg-text">"{m.msg}"</div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:8}}>
                  <div className="msg-author">{m.name}</div>
                  <div className="msg-time">{m.time}</div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* MENU */}
        {tab === "menu" && (
          <div className="section">
            <div className="section-title">Menu</div>
            <div className="section-sub">Choisissez votre repas</div>
            <div style={{fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"#8B4513",marginBottom:10,fontWeight:600}}>Plat principal</div>
            {MEALS.map(m => (
              <div className={`menu-item${selectedMeal===m.id?" selected":""}`} key={m.id} onClick={() => setSelectedMeal(m.id)}>
                <div style={{fontSize:28}}>{m.icon}</div>
                <div style={{flex:1}}>
                  <div className="menu-item-name">{m.name}</div>
                  <div className="menu-item-desc">{m.desc}</div>
                </div>
                <div className="menu-check">{selectedMeal===m.id?"✓":""}</div>
              </div>
            ))}
            <div style={{fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"#8B4513",margin:"16px 0 10px",fontWeight:600}}>Inclus pour tous</div>
            {[{icon:"🍹",n:"Cocktail de bienvenue",d:"Accueil & apéritif"},{icon:"🥗",n:"Entrée du chef",d:"Spécialité locale"},{icon:"🎂",n:"Gâteau de mariage",d:"Pièce montée traditionnelle"}].map((item,i) => (
              <div className="menu-item" key={i} style={{opacity:0.7,cursor:"default"}}>
                <div style={{fontSize:28}}>{item.icon}</div>
                <div style={{flex:1}}><div className="menu-item-name">{item.n}</div><div className="menu-item-desc">{item.d}</div></div>
                <div style={{fontSize:16,color:"#c8860a"}}>✓</div>
              </div>
            ))}
            {selectedMeal && <button className="main-btn" style={{marginTop:14}}>Confirmer mon choix ✓</button>}
          </div>
        )}

        {/* TABLES */}
        {tab === "table" && (
          <div className="section">
            <div className="section-title">Plan de table</div>
            <div className="section-sub">Retrouvez votre place</div>
            {TABLES.map(t => (
              <div className="table-card" key={t.num}>
                <div className="table-header">
                  <div className="table-num">{t.num}</div>
                  <div className="table-name">{t.name}</div>
                </div>
                {t.guests.map((g, i) => (
                  <div className="table-guest" key={i}><div className="table-dot" />{g}</div>
                ))}
              </div>
            ))}
          </div>
        )}

        {/* Bottom Nav */}
        <div className="bottom-nav">
          {NAV.map(n => (
            <button key={n.id} className={`nav-btn${tab===n.id?" active":""}`} onClick={() => setTab(n.id)}>
              <span className="nav-icon">{n.icon}</span>
              <span className="nav-label">{n.label}</span>
            </button>
          ))}
        </div>
      </div>
    </>
  );
}
